import { seller } from "../../config/checkoutConfig";
import { CalculatedFurnitureMaterial } from "../calculateFurnitureMaterials";
import { CalculatedSystemMaterial } from "../calculateSystemMaterials";
import { CalculatorInput } from "../types";
import { getGroundSystemPricing, getGroundSystemTotal, isGroundSystem } from "../groundPricing";

const MATERIAL_NAMES: Record<string, string> = {
  "materials.squareRail":      "Kvadratinis bėgelis",
  "materials.squareRailJoint": "Kvadratinio bėgelio jungtis",
  "materials.squareRailFinish":"Kvadratinio bėgelio past. užbaigimas",
  "materials.m10Screw":        "M10 varžtas 20",
  "materials.m10Nut":          "M10 veržlės su sijonėliu",
  "materials.studs":           "Smeigės",
  "materials.clampG":          "Clamp G",
  "materials.m8Screw20":       "M8 varžtas cilindrine galvute 20",
  "materials.clampV":          "Clamp V",
  "materials.m8Screw":         "M8 varžtas cilindrine galvute 25",
  "materials.m8Nut":           "M8 mėnuliukai",
  "materials.railEDPMMini":    "Bėgelis su EPDM guma mini",
  "materials.specScrew":       "Spec. Savisriegiai bėgeliui",
  "materials.railEDPM40":      "Bėgelis su EPDM guma 40",
  "materials.railEDPM80":      "Bėgelis su EPDM guma 80",
};

function resolveName(name: string): string {
  return MATERIAL_NAMES[name] ?? name;
}

function displayGroundSku(code: string): string {
  return code.replace(/^__GROUND_PRICE__[_-]?/i, "");
}

export interface BuyerInfo {
  name: string;
  email: string;
  phone: string;
  address: string;
}

// ─── Brand colors matching the Word document ──────────────────────────────────
const MAGENTA         = "#CC1E8C";
const DARK_BAR        = "#3D1A35";
const TEXT            = "#1a1a1a";
const MUTED           = "#666666";
const TABLE_HEADER_BG = "#F0F0F0";
const TABLE_ROW_ALT   = "#F8F8F8";
const BORDER          = "#BBBBBB";
const FONT            = "Arial, sans-serif";

// ─── Embedded images (base64) ─────────────────────────────────────────────────
const LOGO_B64   = "";
const EZYS_B64   = "";
const POLINE_B64 = "";
const FLAT_B64   = "";
const ROOF_B64   = "";

// ─── Page dimensions ──────────────────────────────────────────────────────────
const W      = 794;
const MARGIN = 40;
const COL_W  = W - MARGIN * 2;
const ROW_H  = 18;
const LOGO_H = 100;

// ─── Helpers ──────────────────────────────────────────────────────────────────
function fmt(n: number): string {
  return n.toFixed(2).replace(".", ",");
}

function shortCode(code: string): string {
  return (code ?? "").split("/")[0].trim();
}

function getPriceFromMap(code: string, map: Record<string, number>): number | null {
  return map[shortCode(code)] ?? null;
}

function fillR(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, fill: string) {
  ctx.fillStyle = fill;
  ctx.fillRect(x, y, w, h);
}

function cellText(
  ctx: CanvasRenderingContext2D,
  text: string,
  px: number, py: number,
  clipX: number, clipY: number, clipW: number, clipH: number,
) {
  ctx.save();
  ctx.beginPath();
  ctx.rect(clipX + 1, clipY + 1, clipW - 2, clipH - 2);
  ctx.clip();
  ctx.fillText(text, px, py);
  ctx.restore();
}

// ─── Image loader ─────────────────────────────────────────────────────────────
function loadImg(b64: string, mime = "image/jpeg"): Promise<HTMLImageElement> {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload  = () => resolve(img);
    img.onerror = () => resolve(img);
    img.src = `data:${mime};base64,${b64}`;
  });
}

function loadLogo()   { return loadImg(LOGO_B64); }
function loadEzys()   { return loadImg(EZYS_B64); }
function loadPoline() { return loadImg(POLINE_B64); }
function loadFlat()   { return loadImg(FLAT_B64); }
function loadRoof()   { return loadImg(ROOF_B64); }

// ─── Get the correct solar image for a battery type ───────────────────────────
function getSolarImageLoader(batteryType: string): () => Promise<HTMLImageElement> {
  switch (batteryType) {
    case "ezys":          return loadEzys;
    case "poline":        return loadPoline;
    case "ploksciasStogas": return loadFlat;
    case "slaitinisStogas": return loadRoof;
    default:              return loadPoline;
  }
}

// ─── Document title ───────────────────────────────────────────────────────────
function getDocTitle(input: CalculatorInput): { header: string; sub: string } {
  switch (input.batteryType) {
    case "ezys":
      return {
        header: "ANTŽEMINĖ SAULĖS MODULIŲ MONTAVIMO SISTEMA",
        sub: `Ežio saulės modulių montavimo sistema | Matmenys: ${input.moduleLength}x${input.moduleWidth}x${input.moduleThickness}, mm | Kiekis: ${input.moduleCount} | Spalva: ${input.moduleColor}`,
      };
    case "poline":
      return {
        header: "ANTŽEMINĖ SAULĖS MODULIŲ MONTAVIMO SISTEMA",
        sub: `Polinė saulės modulių montavimo sistema | Matmenys: ${input.moduleLength}x${input.moduleWidth}x${input.moduleThickness}, mm | Kiekis: ${input.moduleCount} | Spalva: ${input.moduleColor}`,
      };
    case "ploksciasStogas":
      return {
        header: "PLOKŠČIO STOGO SAULĖS MODULIŲ MONTAVIMO SISTEMA",
        sub: `Sistema: ${input.system ?? ""}  | Matmenys: ${input.moduleLength}x${input.moduleWidth}x${input.moduleThickness}, mm | Kiekis: ${input.moduleCount} | Spalva: ${input.moduleColor} |  Orientacija: ${input.orientation ?? ""}`,
      };
    case "slaitinisStogas":
      return {
        header: "ŠLAITINIO STOGO SAULĖS MODULIŲ MONTAVIMO SISTEMA",
        sub: `Stogo danga: ${input.roofMaterial ?? ""}  | Matmenys: ${input.moduleLength}x${input.moduleWidth}x${input.moduleThickness}, mm | Kiekis: ${input.moduleCount} | Spalva: ${input.moduleColor} |  Montavimo būdas: ${input.mountingMethod ?? ""}`,
      };
    default:
      return { header: "SAULĖS MODULIŲ MONTAVIMO SISTEMA", sub: "" };
  }
}

function getOrderNum(): string {
  const d = new Date();
  return `MK${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, "0")}${String(d.getDate()).padStart(2, "0")}-1`;
}

// ─── Footer: magenta line + dark bar with text ────────────────────────────────
// Matches the Word document footer exactly:
//   • thin magenta line
//   • thin dark bar below it
//   • company info text centred in the dark bar
function drawPageFooter(ctx: CanvasRenderingContext2D, pageH: number) {
  const lineH = 3;
  const fy    = pageH - lineH - 22;

  // Magenta line only
  fillR(ctx, MARGIN, fy, COL_W, lineH, MAGENTA);

  // Footer text on white background
  ctx.font      = `9.5px ${FONT}`;
  ctx.fillStyle = MUTED;
  ctx.textAlign = "center";
  const txt = `„Metalo kaprizas", UAB  ●  Įm. kodas ${seller.companyCode}  ●  ${seller.address}` +
              `   Tel. nr. ${seller.phone}  ●  El. paštas ${seller.email}`;
  ctx.fillText(txt, W / 2, fy + lineH + 16);
}

// ─── Cover page header (logo only) ────────────────────────────────────────────
function drawLogoHeader(ctx: CanvasRenderingContext2D, logo: HTMLImageElement) {
  if (logo.complete && logo.naturalWidth > 0) {
    const aspect = logo.naturalWidth / logo.naturalHeight;
    ctx.drawImage(logo, MARGIN, MARGIN, LOGO_H * aspect, LOGO_H);
  }
  // Magenta line
  fillR(ctx, MARGIN, MARGIN + LOGO_H + 4, COL_W, 3.5, MAGENTA);
}

// ─── Materials-page header (logo + offer info + seller/buyer) ─────────────────
function drawPageHeader(
  ctx: CanvasRenderingContext2D,
  logo: HTMLImageElement,
  buyer: BuyerInfo,
  input: CalculatorInput,
  offerNum: string,
  startY: number,
): number {
  let y = startY;

  // Logo
  if (logo.complete && logo.naturalWidth > 0) {
    const aspect = logo.naturalWidth / logo.naturalHeight;
    ctx.drawImage(logo, MARGIN, y, LOGO_H * aspect, LOGO_H);
  }
  // Magenta line
  fillR(ctx, MARGIN, y + LOGO_H + 3, COL_W, 3.5, MAGENTA);
  y += LOGO_H + 14;

  // Offer number
  ctx.font      = `14px ${FONT}`;
  ctx.fillStyle = TEXT;
  ctx.textAlign = "center";
  ctx.fillText(`Komercinis pasiūlymas Nr. ${offerNum}`, W / 2, y + 14);
  y += 32;

  // Document title
  const { header, sub } = getDocTitle(input);
  ctx.font      = `16px ${FONT}`;
  ctx.fillStyle = TEXT;
  ctx.textAlign = "center";
  ctx.fillText(header, W / 2, y + 14);
  y += 24;

  if (sub) {
    ctx.font      = `12px ${FONT}`;
    ctx.fillStyle = MUTED;
    ctx.textAlign = "center";
    ctx.fillText(sub, W / 2, y + 12);
    y += 20;
  }
  y += 14;

  // Seller / Buyer columns
  const HALF = Math.floor(COL_W / 2) - 6;

  ctx.font      = `bold 11px ${FONT}`;
  ctx.fillStyle = MUTED;
  ctx.textAlign = "left";
  ctx.fillText("Pardavėjas", MARGIN, y + 11);
  ctx.font      = `bold 11.5px ${FONT}`;
  ctx.fillStyle = TEXT;
  ctx.fillText(seller.name, MARGIN, y + 26);
  ctx.font      = `10.5px ${FONT}`;
  ctx.fillStyle = MUTED;
  [
    `Įm. kodas  ${seller.companyCode}`,
    `PVM kodas  ${seller.vatCode}`,
    `Adresas  ${seller.address}`,
    `Tel. nr.  ${seller.phone}`,
    `El. paštas  ${seller.email}`,
    `A.s.  ${seller.iban}`,
    `Bankas  ${seller.bank}`,
  ].forEach((ln, i) => ctx.fillText(ln, MARGIN, y + 40 + i * 13));

  const bx = MARGIN + HALF + 12;
  ctx.font      = `bold 11px ${FONT}`;
  ctx.fillStyle = MUTED;
  ctx.textAlign = "left";
  ctx.fillText("Pirkėjas", bx, y + 11);
  ctx.font      = `bold 11.5px ${FONT}`;
  ctx.fillStyle = TEXT;
  ctx.fillText(buyer.name || "_________________________", bx, y + 26);
  ctx.font      = `10.5px ${FONT}`;
  ctx.fillStyle = MUTED;
  [
    `Adresas: ${buyer.address || "__________________________"}`,
    `Tel.: ${buyer.phone  || "__________________________"}`,
    `El. paštas: ${buyer.email || "__________________________"}`,
  ].forEach((ln, i) => ctx.fillText(ln, bx, y + 40 + i * 13));

  y += 122;

  // Separator line
  ctx.strokeStyle = BORDER;
  ctx.lineWidth   = 0.5;
  ctx.beginPath();
  ctx.moveTo(MARGIN, y);
  ctx.lineTo(MARGIN + COL_W, y);
  ctx.stroke();
  y += 12;

  return y;
}

// ─── Table renderer ───────────────────────────────────────────────────────────
type Align = "center" | "left" | "right";
interface ColDef  { label: string; width: number; align: Align; }
interface RowCell { text: string; align?: Align; }

function drawTable(
  ctx: CanvasRenderingContext2D,
  x: number, startY: number,
  cols: ColDef[], rows: RowCell[][], totalWidth: number,
): number {
  let y = startY;

  // Header
  fillR(ctx, x, y, totalWidth, ROW_H, TABLE_HEADER_BG);
  ctx.font      = `bold 9.5px ${FONT}`;
  ctx.fillStyle = TEXT;
  let cx = x;
  for (const col of cols) {
    ctx.strokeStyle = BORDER; ctx.lineWidth = 0.5;
    ctx.strokeRect(cx + 0.25, y + 0.25, col.width - 0.5, ROW_H - 0.5);
    const tx = col.align === "left" ? cx + 4 : cx + col.width / 2;
    ctx.textAlign = col.align === "left" ? "left" : "center";
    cellText(ctx, col.label, tx, y + 12, cx, y, col.width, ROW_H);
    cx += col.width;
  }
  y += ROW_H;

  for (let ri = 0; ri < rows.length; ri++) {
    const row = rows[ri];
    const isTotalRow = row[0]?.text === "__total__";
    fillR(ctx, x, y, totalWidth, ROW_H, isTotalRow ? TABLE_HEADER_BG : ri % 2 === 0 ? "#ffffff" : TABLE_ROW_ALT);
    ctx.font = isTotalRow ? `bold 10px ${FONT}` : `10px ${FONT}`;

    let dcx = x;
    for (let ci = 0; ci < cols.length; ci++) {
      const col  = cols[ci];
      const cell = row[ci] ?? { text: "" };
      ctx.strokeStyle = BORDER; ctx.lineWidth = 0.5;
      ctx.strokeRect(dcx + 0.25, y + 0.25, col.width - 0.5, ROW_H - 0.5);

      if (isTotalRow && ci < cols.length - 2) { dcx += col.width; continue; }

      const align = isTotalRow
        ? (ci === cols.length - 2 ? "right" : ci === cols.length - 1 ? "center" : "left")
        : (cell.align ?? col.align);

      ctx.fillStyle = isTotalRow && ci >= cols.length - 2 ? MAGENTA : TEXT;
      ctx.textAlign = align === "left" ? "left" : align === "right" ? "right" : "center";

      let tx: number;
      if (align === "left")       tx = dcx + 4;
      else if (align === "right") tx = dcx + col.width - 4;
      else                        tx = dcx + col.width / 2;

      cellText(ctx, cell.text, tx, y + 12, dcx, y, col.width, ROW_H);
      dcx += col.width;
    }
    y += ROW_H;
  }
  return y;
}

// ─── Page 0: Cover page ───────────────────────────────────────────────────────
async function buildCoverPage(
  input: CalculatorInput,
  logo: HTMLImageElement,
): Promise<HTMLCanvasElement> {
  const H     = 1123;
  const SCALE = 2;
  const canvas = document.createElement("canvas");
  canvas.width  = W * SCALE;
  canvas.height = H * SCALE;
  const ctx = canvas.getContext("2d")!;
  ctx.scale(SCALE, SCALE);
  ctx.fillStyle = "#fff";
  ctx.fillRect(0, 0, W, H);

  // Header logo + magenta line
  drawLogoHeader(ctx, logo);

  // Document title — centred vertically in upper third
  const { header, sub } = getDocTitle(input);
  const titleY = 220;

  ctx.font      = `16px ${FONT}`;
  ctx.fillStyle = TEXT;
  ctx.textAlign = "center";
  ctx.fillText(header, W / 2, titleY);

  if (sub) {
    ctx.font      = `11px ${FONT}`;
    ctx.fillStyle = MUTED;
    ctx.fillText(sub, W / 2, titleY + 22);
  }

  // Solar type illustration — centred
  const solarLoader = getSolarImageLoader(input.batteryType);
  const solarImg    = await solarLoader();
  if (solarImg.complete && solarImg.naturalWidth > 0) {
    const maxW   = COL_W - 40;
    const maxH   = 420;
    const aspect = solarImg.naturalWidth / solarImg.naturalHeight;
    let dw = maxW, dh = maxW / aspect;
    if (dh > maxH) { dh = maxH; dw = dh * aspect; }
    const dx = MARGIN + (COL_W - dw) / 2;
    const dy = titleY + 50;
    ctx.drawImage(solarImg, dx, dy, dw, dh);
  }

  // Footer
  drawPageFooter(ctx, H);

  return canvas;
}

// ─── Page 1: Materials ────────────────────────────────────────────────────────
async function buildMaterialsPage(
  buyer: BuyerInfo,
  input: CalculatorInput,
  systemMaterials: CalculatedSystemMaterial[],
  furnitureMaterials: CalculatedFurnitureMaterial[],
  offerNum: string,
  logo: HTMLImageElement,
): Promise<HTMLCanvasElement> {
  const SCALE    = 2;
  const isGround = isGroundSystem(input);
  const prices   = input.productPrices ?? {};
  const groundPricing = isGround ? getGroundSystemPricing(input, prices) : null;
  const groundTotal = isGround ? getGroundSystemTotal(input, prices) : 0;

  const cNr    = 26;
  const cCode  = 100;
  const cQty   = 44;
  const cLen   = isGround ? 60 : 0;
  const cPrice = 64;
  const cSum   = 68;
  const cName  = COL_W - cNr - cCode - cQty - cLen - cPrice - cSum;

  const sysCols: ColDef[] = [
    { label: "Nr.",          width: cNr,    align: "center" },
    { label: "Kodas",        width: cCode,  align: "center" },
    { label: "Pavadinimas",  width: cName,  align: "left"   },
    { label: "Kiekis",       width: cQty,   align: "center" },
    ...(isGround ? [{ label: "Ilgis, mm", width: cLen, align: "center" as Align }] : []),
    { label: "Kaina, €", width: cPrice, align: "center" as Align },
    { label: "Suma, €",  width: cSum,   align: "center" as Align },
  ];

  const sysRows: RowCell[][] = isGround && groundPricing
    ? [[
        { text: "1" },
        { text: displayGroundSku(groundPricing.code) },
        { text: resolveName(groundPricing.name), align: "left" },
        { text: String(input.moduleCount) },
        { text: String(groundPricing.moduleWidth) },
        { text: fmt(groundPricing.unitPrice) },
        { text: fmt(groundTotal) },
      ]]
    : systemMaterials.map((m, i) => {
        const price  = getPriceFromMap(m.code ?? "", prices);
        const rowSum = price != null ? price * m.quantity : null;
        return [
          { text: String(i + 1) },
          { text: shortCode(m.code ?? "") },
          { text: resolveName(m.name), align: "left" },
          { text: String(m.quantity) },
          ...(isGround ? [{ text: m.length != null ? String(m.length) : "–" }] : []),
          { text: fmt(price ?? 0) },
          { text: fmt(rowSum ?? 0) },
        ];
      });
  const sysTotal = isGround
    ? groundTotal
    : systemMaterials.reduce((sum, m) => {
        const price = getPriceFromMap(m.code ?? "", prices);
        return price != null ? sum + price * m.quantity : sum;
      }, 0);
  sysRows.push([
    { text: "__total__" },
    ...Array(sysCols.length - 3).fill({ text: "" }),
    { text: "Viso:" },
    { text: fmt(sysTotal) + " €" },
  ]);

  const fCode  = 72;
  const fQty   = 44;
  const fPrice = 64;
  const fSum   = 68;
  const fName  = COL_W - cNr - fCode - fQty - fPrice - fSum;

  const furnCols: ColDef[] = [
    { label: "Nr.",         width: cNr,   align: "center" },
    { label: "Kodas",       width: fCode, align: "center" },
    { label: "Pavadinimas", width: fName, align: "left"   },
    { label: "Kiekis",      width: fQty,  align: "center" },
    { label: "Kaina, €", width: fPrice, align: "center" as Align },
    { label: "Suma, €",  width: fSum,   align: "center" as Align },
  ];

  let furnTotal = 0;
  const furnRows: RowCell[][] = furnitureMaterials.map((m, i) => {
    const sku    = m.sku ?? "";
    const price  = prices[sku] ?? null;
    const rowSum = price != null ? price * m.quantity : null;
    if (rowSum != null) furnTotal += rowSum;
    const displayName = m.name.replace(/\s*\([^)]+\)$/, "");
    return [
      { text: String(i + 1) },
      { text: sku },
      { text: displayName, align: "left" },
      { text: String(m.quantity) },
      { text: fmt(price ?? 0) },
      { text: fmt(rowSum ?? 0) },
    ];
  });
  furnRows.push([
    { text: "__total__" },
    ...Array(furnCols.length - 3).fill({ text: "" }),
    { text: "Viso:" },
    { text: fmt(furnTotal) + " €" },
  ]);

  const hdrH  = LOGO_H + 14 + 30 + 20 + 18 + 14 + 110 + 12;
  const secH  = 20;
  const sysH  = ROW_H * (sysRows.length + 1);
  const furnH = !isGround && furnitureMaterials.length > 0 ? ROW_H * (furnRows.length + 1) + secH + 14 : 0;
  const H     = Math.max(1123, MARGIN + hdrH + secH + sysH + 14 + furnH + 30 + 40 + 20);

  const canvas  = document.createElement("canvas");
  canvas.width  = W * SCALE;
  canvas.height = H * SCALE;
  const ctx     = canvas.getContext("2d")!;
  ctx.scale(SCALE, SCALE);
  ctx.fillStyle = "#fff";
  ctx.fillRect(0, 0, W, H);

  let y = MARGIN;
  y = drawPageHeader(ctx, logo, buyer, input, offerNum, y);

  ctx.font      = `bold 11px ${FONT}`;
  ctx.fillStyle = TEXT;
  ctx.textAlign = "left";
  ctx.fillText("SISTEMOS MEDŽIAGŲ KIEKIŲ ŽINIARAŠTIS", MARGIN, y + 13);
  y += 22;
  y = drawTable(ctx, MARGIN, y, sysCols, sysRows, COL_W);
  y += 16;

  if (!isGround && furnitureMaterials.length > 0) {
    ctx.font      = `bold 11px ${FONT}`;
    ctx.fillStyle = TEXT;
    ctx.textAlign = "left";
    ctx.fillText("FURNITŪROS MEDŽIAGŲ KIEKIŲ ŽINIARAŠTIS", MARGIN, y + 13);
    y += 20;
    y = drawTable(ctx, MARGIN, y, furnCols, furnRows, COL_W);
    y += 14;
  }

  const grand = isGround ? sysTotal : sysTotal + furnTotal;
  fillR(ctx, MARGIN, y, COL_W, 24, MAGENTA);
  ctx.font      = `bold 12px ${FONT}`;
  ctx.fillStyle = "#ffffff";
  ctx.textAlign = "right";
  ctx.fillText(`Bendra suma be PVM:   ${fmt(grand)} €`, MARGIN + COL_W - 10, y + 16);

  drawPageFooter(ctx, H);
  return canvas;
}

// ─── Page 2: Drawing / schema ─────────────────────────────────────────────────
function buildCanvasPage(
  canvasDataUrl: string,
  buyer: BuyerInfo,
  input: CalculatorInput,
  offerNum: string,
  logo: HTMLImageElement,
): Promise<HTMLCanvasElement> {
  const H = 1123;
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement("canvas");
      canvas.width  = W * 2;
      canvas.height = H * 2;
      const ctx = canvas.getContext("2d")!;
      ctx.scale(2, 2);
      ctx.fillStyle = "#fff";
      ctx.fillRect(0, 0, W, H);

      let y = MARGIN;
      y = drawPageHeader(ctx, logo, buyer, input, offerNum, y);

      ctx.font      = `bold 11px ${FONT}`;
      ctx.fillStyle = TEXT;
      ctx.textAlign = "left";
      ctx.fillText("UŽSAKYMO SCHEMA (brėžinys)", MARGIN, y + 13);
      y += 20;

      const availW = COL_W;
      const availH = H - y - 50;
      const aspect = img.naturalWidth / img.naturalHeight;
      let dw = availW, dh = dw / aspect;
      if (dh > availH) { dh = availH; dw = dh * aspect; }
      const dx = MARGIN + (availW - dw) / 2;

      ctx.strokeStyle = BORDER; ctx.lineWidth = 0.5;
      ctx.strokeRect(dx - 1, y - 1, dw + 2, dh + 2);
      ctx.drawImage(img, dx, y, dw, dh);

      drawPageFooter(ctx, H);
      resolve(canvas);
    };
    img.onerror = () => resolve(document.createElement("canvas"));
    img.src = canvasDataUrl;
  });
}

// ─── Public API ───────────────────────────────────────────────────────────────
export async function buildPdfPages(
  buyer: BuyerInfo,
  input: CalculatorInput,
  systemMaterials: CalculatedSystemMaterial[],
  furnitureMaterials: CalculatedFurnitureMaterial[],
): Promise<{ offerNum: string; imgs: string[] }> {
  const offerNum = getOrderNum();
  const logo     = await loadLogo();

  const cover  = await buildCoverPage(input, logo);
  const page1  = await buildMaterialsPage(buyer, input, systemMaterials, furnitureMaterials, offerNum, logo);
  const page2  = input.canvasImageDataUrl
    ? await buildCanvasPage(input.canvasImageDataUrl, buyer, input, offerNum, logo)
    : null;

  const imgs = [cover, page1, ...(page2 ? [page2] : [])].map((c) => c.toDataURL("image/png"));
  return { offerNum, imgs };
}

export async function generateCommercialProposalPdf(
  buyer: BuyerInfo,
  input: CalculatorInput,
  systemMaterials: CalculatedSystemMaterial[],
  furnitureMaterials: CalculatedFurnitureMaterial[],
): Promise<string[]> {
  const { offerNum, imgs } = await buildPdfPages(buyer, input, systemMaterials, furnitureMaterials);

  const { jsPDF } = await import("jspdf");
  const pdf   = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const pageW = pdf.internal.pageSize.getWidth();
  const pageH = pdf.internal.pageSize.getHeight();

  for (let i = 0; i < imgs.length; i++) {
    if (i > 0) pdf.addPage();
    pdf.addImage(imgs[i], "PNG", 0, 0, pageW, pageH, undefined, "FAST");
  }

  // const filename = `Komercinis-pasiulymas-${offerNum}.pdf`;
  // pdf.save(filename);
  return [pdf.output("datauristring")];
}